// Array element access - O(1)
const myArray: number[] = [10, 25, 3, 47, 18];

// Access first element
console.log(myArray[0]); // 10

// Access last element
console.log(myArray[myArray.length - 1]); // 18

// Safe access with bounds checking
function safeAccess<T>(arr: T[], index: number): T | undefined {
    if (index >= 0 && index < arr.length) {
        return arr[index];
    }
    return undefined;
}

console.log(safeAccess(myArray, 2)); // 3
console.log(safeAccess(myArray, 10)); // undefined

