// Array element insertion - O(n)
function insertElement<T>(arr: T[], index: number, element: T): T[] {
    if (index < 0 || index > arr.length) {
        throw new Error("Index out of bounds");
    }

    const newArray = [...arr];
    newArray.splice(index, 0, element);
    return newArray;
}

// Example usage
const myArray: number[] = [10, 25, 3, 47, 18];
const newArray = insertElement(myArray, 2, 99);
console.log(newArray); // [10, 25, 99, 3, 47, 18]

