// Array element insertion - O(n)
#include <iostream>
#include <vector>
using namespace std;

vector<int> insertElement(const vector<int>& arr, int index, int element) {
    if (index < 0 || index > arr.size()) {
        throw out_of_range("Index out of bounds");
    }

    vector<int> newArray = arr;
    newArray.insert(newArray.begin() + index, element);
    return newArray;
}

int main() {
    vector<int> myArray = {10, 25, 3, 47, 18};
    vector<int> newArray = insertElement(myArray, 2, 99);

    for (int val : newArray) {
        cout << val << " ";
    }
    cout << endl; // Output: 10 25 99 3 47 18
    return 0;
}

