import java.util.*;

public class ArrayInsertion {
    public static List<Integer> insertElement(int[] arr, int index, int element) {
        if (index < 0 || index > arr.length) {
            throw new IndexOutOfBoundsException("Index out of bounds");
        }

        List<Integer> newArray = new ArrayList<>();
        for (int i = 0; i < arr.length; i++) {
            if (i == index) {
                newArray.add(element);
            }
            newArray.add(arr[i]);
        }
        if (index == arr.length) {
            newArray.add(element);
        }
        return newArray;
    }

    public static void main(String[] args) {
        int[] myArray = {10, 25, 3, 47, 18};
        List<Integer> newArray = insertElement(myArray, 2, 99);
        System.out.println(newArray); // [10, 25, 99, 3, 47, 18]
    }
}

