// Array element insertion - O(n)
#include <stdio.h>
#include <stdlib.h>

int* insertElement(int arr[], int size, int index, int element, int* newSize) {
    if (index < 0 || index > size) {
        printf("Error: Index out of bounds\n");
        return NULL;
    }

    *newSize = size + 1;
    int* newArray = malloc(*newSize * sizeof(int));

    for (int i = 0, j = 0; i < *newSize; i++) {
        if (i == index) {
            newArray[i] = element;
        } else {
            newArray[i] = arr[j++];
        }
    }

    return newArray;
}

int main() {
    int myArray[] = {10, 25, 3, 47, 18};
    int size = 5, newSize;
    int* newArray = insertElement(myArray, size, 2, 99, &newSize);

    for (int i = 0; i < newSize; i++) {
        printf("%d ", newArray[i]);
    }
    printf("\n"); // Output: 10 25 99 3 47 18

    free(newArray);
    return 0;
}

