// Linear search - O(n)
function linearSearch<T>(arr: T[], target: T): number {
    for (let i = 0; i < arr.length; i++) {
        if (arr[i] === target) {
            return i; // Return found index
        }
    }
    return -1; // Not found
}

// Binary search (requires sorted array) - O(log n)
function binarySearch(arr: number[], target: number): number {
    let left = 0;
    let right = arr.length - 1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);

        if (arr[mid] === target) {
            return mid;
        } else if (arr[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return -1; // Not found
}

// Example usage
const myArray: number[] = [3, 10, 15, 18, 25, 47, 92];
console.log(binarySearch(myArray, 25)); // Output: 4

